// TestKeywordClassifier_ExtractTemporal_Yesterday tests "yesterday" detection.
func TestKeywordClassifier_ExtractTemporal_Yesterday(t *testing.T) {
	classifier := &KeywordClassifier{}
	ctx := context.Background()

	tests := []struct {
		name  string
		query string
	}{
		{"lowercase", "what happened yesterday?"},
		{"uppercase", "What happened YESTERDAY?"},
		{"mixed_case", "Show me Yesterday's events"},
		{"with_punctuation", "events from yesterday."},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := classifier.ClassifyQuery(ctx, tt.query)

			if result == nil {
				t.Fatal("expected non-nil SearchOptions")
			}

			if result.TimeRange == nil {
				t.Fatal("expected TimeRange to be populated for 'yesterday' query")
			}

			// Yesterday should be start of yesterday to end of yesterday
			now := time.Now()
			yesterdayStart := time.Date(now.Year(), now.Month(), now.Day()-1, 0, 0, 0, 0, now.Location())
			yesterdayEnd := time.Date(now.Year(), now.Month(), now.Day()-1, 23, 59, 59, 999999999, now.Location())

			// Allow 1 second tolerance for test execution time
			if result.TimeRange.Start.Before(yesterdayStart.Add(-time.Second)) ||
				result.TimeRange.Start.After(yesterdayStart.Add(time.Second)) {
				t.Errorf("Start time mismatch: got %v, want ~%v", result.TimeRange.Start, yesterdayStart)
			}

			if result.TimeRange.End.Before(yesterdayEnd.Add(-time.Second)) ||
				result.TimeRange.End.After(yesterdayEnd.Add(time.Second)) {
				t.Errorf("End time mismatch: got %v, want ~%v", result.TimeRange.End, yesterdayEnd)
			}

			if result.Query != tt.query {
				t.Errorf("Query field should be preserved: got %q, want %q", result.Query, tt.query)
			}
		})
	}
}

