// TestKeywordClassifier_WithContext verifies context is handled properly.
func TestKeywordClassifier_WithContext(t *testing.T) {
	classifier := &KeywordClassifier{}

	t.Run("with_cancelled_context", func(t *testing.T) {
		ctx, cancel := context.WithCancel(context.Background())
		cancel() // Cancel immediately

		// Should still return result even with cancelled context
		// (keyword matching is synchronous, doesn't use context for I/O)
		result := classifier.ClassifyQuery(ctx, "yesterday's events")

		if result == nil {
			t.Fatal("expected non-nil SearchOptions even with cancelled context")
		}

		if result.TimeRange == nil {
			t.Error("should still detect temporal pattern with cancelled context")
		}
	})

	t.Run("with_deadline", func(t *testing.T) {
		ctx, cancel := context.WithTimeout(context.Background(), 1*time.Millisecond)
		defer cancel()

		time.Sleep(2 * time.Millisecond) // Ensure deadline passes

		result := classifier.ClassifyQuery(ctx, "similar to sensor-001")

		if result == nil {
			t.Fatal("expected non-nil SearchOptions even with expired deadline")
		}

		if !result.UseEmbeddings {
			t.Error("should still detect similarity pattern with expired deadline")
		}
	})
}

